    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by normalized term frequency
/// and returns the highest-scoring ones in their original order.
/// </summary>
public partial class DocumentSummarizationService : IDocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","of","in","to","for",
        "with","on","at","from","by","about","as","into","through","during",
        "before","after","above","below","between","out","off","over","under",
        "again","further","then","once","it","its","this","that","these",
        "those","i","me","my","we","our","you","your","he","him","his","she",
        "her","they","them","their","what","which","who","whom","when","where",
        "why","how","not","no","nor","so","if","each","every","all","both",
        "few","more","most","other","some","such","only","own","same","than",
        "too","very","just","also","there","here"
    };

    public (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count == 0)
            return (string.Empty, 0, 0);

        if (sentences.Count <= maxSentences)
            return (string.Join(" ", sentences), sentences.Count, sentences.Count);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentence indices, then sort by original order.
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));
        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        if (freq.Count == 0)
            return [];

        double maxFreq = freq.Values.Max();
        return freq.ToDictionary(kv => kv.Key, kv => kv.Value / maxFreq, StringComparer.OrdinalIgnoreCase);
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, double> wordFrequencies)
    {
        return sentences.Select(sentence =>
        {
            var words = Tokenize(sentence);
            if (words.Count == 0) return 0;
            return words.Sum(w => wordFrequencies.GetValueOrDefault(w)) / words.Count;
        }).ToList();
    }

    private static List<string> Tokenize(string text) =>
        WordRegex().Matches(text).Select(m => m.Value).ToList();

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizationService;

    public SummarizeController(IDocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _summarizationService.Summarize(
            request.DocumentText,
            request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

